from flask import Flask, request, send_file
import os

app = Flask(__name__)

# Mock invoices directory and invoice IDs
INVOICES_DIR = 'invoices'
if not os.path.exists(INVOICES_DIR):
    os.makedirs(INVOICES_DIR)

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    # Check if the invoice exists
    invoice_path = os.path.join(INVOICES_DIR, f'{invoice_id}.pdf')
    if not os.path.exists(invoice_path):
        return "Invoice not found", 404

    # Send the file for download
    return send_file(invoice_path, as_attachment=True)

